/**
 * tokens.js — flat maps parsed from tokens.baseline.json
 *
 * Values are sourced directly from book/research/motion/tokens.baseline.json.
 * No Style Dictionary is used — manual resolution for simplicity.
 *
 * Exports:
 *   DURATION          — primitive durations { "50": "50ms", ... }
 *   EASING            — primitive easing curves { linear: [0,0,1,1], ... }
 *   SEMANTIC_DURATION — semantic duration aliases { instant: "50ms", ... }
 *   SEMANTIC_EASING   — semantic easing aliases { enter: [0,0,0.2,1], ... }
 *   SPRING_CONFIGS    — spring physics params { crisp: {...}, ... }
 *   TRANSITIONS       — resolved composite transitions { enter: {...}, ... }
 */

// ---------------------------------------------------------------------------
// Primitive durations — from tokens.baseline.json > duration
// ---------------------------------------------------------------------------
export const DURATION = {
  '50':  '50ms',
  '100': '100ms',
  '150': '150ms',
  '200': '200ms',
  '300': '300ms',
  '400': '400ms',
  '500': '500ms',
  '700': '700ms',
};

// ---------------------------------------------------------------------------
// Primitive easing curves — from tokens.baseline.json > easing
// Values are [x1, y1, x2, y2] cubic-bezier control points
// ---------------------------------------------------------------------------
export const EASING = {
  linear:   [0, 0, 1, 1],
  standard:  [0.4, 0, 0.2, 1],
  enter:     [0, 0, 0.2, 1],
  exit:      [0.4, 0, 1, 1],
  emphasize: [0.2, 0, 0, 1],
};

// ---------------------------------------------------------------------------
// Semantic duration aliases — from tokens.baseline.json > motion.duration
// References resolved to concrete values from DURATION
// ---------------------------------------------------------------------------
export const SEMANTIC_DURATION = {
  instant:   '50ms',   // {duration.50}
  fast:      '100ms',  // {duration.100}
  default:   '200ms',  // {duration.200}
  slow:      '400ms',  // {duration.400}
  deliberate:'700ms',  // {duration.700}
};

// ---------------------------------------------------------------------------
// Semantic easing aliases — from tokens.baseline.json > motion.easing
// References resolved to concrete values from EASING
// ---------------------------------------------------------------------------
export const SEMANTIC_EASING = {
  enter:    [0, 0, 0.2, 1],    // {easing.enter}
  exit:     [0.4, 0, 1, 1],    // {easing.exit}
  move:     [0.4, 0, 0.2, 1],  // {easing.standard}
  emphasize:[0.2, 0, 0, 1],    // {easing.emphasize}
};

// ---------------------------------------------------------------------------
// Spring configs — from tokens.baseline.json > spring.config
// Values exactly as in the JSON $value fields
// ---------------------------------------------------------------------------
export const SPRING_CONFIGS = {
  crisp:  { stiffness: 500, damping: 45, mass: 1 },
  gentle: { stiffness: 200, damping: 20, mass: 1 },
  bouncy: { stiffness: 300, damping: 12, mass: 1 },
};

