// ---------------------------------------------------------------------------
// Helper: format cubic-bezier array as CSS string
// ---------------------------------------------------------------------------
export function cubicBezierCSS([x1, y1, x2, y2]) {
  return `cubic-bezier(${x1}, ${y1}, ${x2}, ${y2})`;
}
