// ---------------------------------------------------------------------------
// Story 1 — TwoAxisMatrix
// ---------------------------------------------------------------------------
export const TwoAxisMatrix = {
  name: 'Two-axis matrix',
  render: () => {
    const depthHeaders = [
      'Depth 1: Scalar',
      'Depth 2: Recipe',
      'Depth 3: Composite',
      'Depth 4: Orchestration',
      'Depth 5: Intent object',
    ];
    const levels = ['Primitive', 'Semantic', 'Application', 'Component'];
    const depthKeys = ['scalar', 'recipe', 'composite', 'orchestration', 'intent'];

    function buildCell(level, depthKey) {
      const key = `${level.toLowerCase()}-${depthKey}`;
      const cell = MATRIX_CELLS[key];
      if (!cell || cell.empty) {
        return `<td><div class="cell-empty"></div></td>`;
      }
      if (cell.frontier) {
        return `
          <td>
            <div class="cell-frontier" data-cell="${key}">
              <div class="cell-token-name">${cell.tokens.join('\n')}</div>
              <div class="cell-label">${cell.label}</div>
              <span class="cell-badge">planned</span>
            </div>
          </td>
        `;
      }
      return `
        <td>
          <div class="cell-populated" data-cell="${key}">
            <div class="cell-token-name">${cell.tokens.join('\n')}</div>
            <div class="cell-label">${cell.label}</div>
            <span class="cell-badge">depth ${cell.depth}</span>
          </div>
        </td>
      `;
    }

    const thead = `
      <thead>
        <tr>
          <th class="row-header"></th>
          ${depthHeaders.map(h => `<th>${h}</th>`).join('')}
        </tr>
      </thead>
    `;

    const tbody = `
      <tbody>
        ${levels.map(level => `
          <tr>
            <td class="row-header-cell">${level}</td>
            ${depthKeys.map(dk => buildCell(level, dk)).join('')}
          </tr>
        `).join('')}
      </tbody>
    `;

    const el = document.createElement('div');
    el.innerHTML = `
      <style>${baseStyles}</style>
      <div class="page">
        <div class="page-title">Motion / Matrix</div>
        <div class="page-subtitle">Two-axis matrix</div>
        <div class="page-description">
          Abstraction level (rows) crossed with composition depth (columns).
          Click a populated cell to see its token definition and trigger its animation.
          Gray dashed cells represent gaps in the current token set.
          Amber cells are planned but not yet implemented in any production system.
        </div>
        <div style="overflow-x: auto;">
          <table class="matrix-table">
            ${thead}
            ${tbody}
          </table>
        </div>
        <div class="detail-panel detail-hidden" id="detailPanel">
          <div class="detail-title" id="detailTitle"></div>
          <div id="detailBody"></div>
          <div id="detailAnimation" style="margin-top: 16px; display: none;">
            <div id="animBox" style="
              width: 80px; height: 40px; background: #888; border-radius: 6px;
              display: flex; align-items: center; justify-content: center;
              color: #fff; font-size: 11px; font-weight: 600;
            ">ref</div>
          </div>
        </div>
      </div>
    `;

    const detailPanel = el.querySelector('#detailPanel');
    const detailTitle = el.querySelector('#detailTitle');
    const detailBody = el.querySelector('#detailBody');
    const detailAnimation = el.querySelector('#detailAnimation');
    const animBox = el.querySelector('#animBox');
    let selectedCell = null;

    el.querySelectorAll('[data-cell]').forEach((cellEl) => {
      cellEl.addEventListener('click', () => {
        const key = cellEl.dataset.cell;
        const cell = MATRIX_CELLS[key];

        // Deselect previous
        if (selectedCell) selectedCell.classList.remove('selected');
        cellEl.classList.add('selected');
        selectedCell = cellEl;

        detailPanel.classList.remove('detail-hidden');
        detailTitle.textContent = cell.tokens.join(', ');
        detailBody.innerHTML = `<div class="detail-pre">${cell.label}</div>`;

        if (cell.animate) {
          detailAnimation.style.display = 'block';
          // Reset and run
          animBox.style.opacity = '1';
          animBox.style.transform = 'none';
          setTimeout(() => {
            cell.animate(animBox);
          }, 50);
        } else {
          detailAnimation.style.display = 'none';
        }
      });
    });

    return el;
  },
};

