export const DepthProgression = {
  name: 'Depth progression',
  render: () => {
    const springResult = springToLinear(500, 45, 1);

    const panels = [
      {
        depth: 1,
        label: 'Scalar',
        token: 'duration.400',
        value: '"400ms"',
        description: 'A raw value. No composition, no semantic meaning. The atom.',
        animate: (el) => el.animate([{ opacity: 0.3 }, { opacity: 1 }], { duration: 400, easing: 'cubic-bezier(0,0,0.2,1)', fill: 'forwards' }),
      },
      {
        depth: 2,
        label: 'Recipe',
        token: 'spring.config.crisp',
        value: '{\n  stiffness: 500,\n  damping: 45,\n  mass: 1\n}',
        description: 'A structured value. Still primitive — but requires a resolver to produce CSS.',
        animate: (el) => {
          const { css, duration } = springResult;
          return el.animate([{ transform: 'scale(0.8)' }, { transform: 'scale(1)' }], { duration, easing: css, fill: 'forwards' });
        },
      },
      {
        depth: 3,
        label: 'Composite',
        token: 'motion.transition.enter',
        value: '{\n  duration: motion.duration.slow,\n  easing: motion.easing.enter\n}',
        description: 'References other tokens. Semantic meaning through combination.',
        animate: (el) => el.animate([{ opacity: 0, transform: 'translateY(8px)' }, { opacity: 1, transform: 'translateY(0)' }], { duration: 400, easing: 'cubic-bezier(0,0,0.2,1)', fill: 'forwards' }),
      },
      {
        depth: 4,
        label: 'Orchestration',
        token: 'stagger.list',
        value: '{\n  interval: 20ms,\n  from: "start",\n  cap: 500ms\n}',
        description: 'Requires context (element count) to resolve. Describes a relationship, not a value.',
        animate: (el) => {
          const delays = [0, 20, 40, 60];
          delays.forEach((delay, i) => {
            const child = el.querySelectorAll ? el.querySelectorAll('.mini-item')[i] : null;
            if (!child) return;
            child.animate([{ opacity: 0, transform: 'translateY(6px)' }, { opacity: 1, transform: 'translateY(0)' }], { duration: 300, easing: 'cubic-bezier(0,0,0.2,1)', delay, fill: 'forwards' });
          });
          return { finished: Promise.resolve() };
        },
        customRef: `
          <div style="display:flex;flex-direction:column;gap:4px;width:100%;">
            ${[0,1,2,3].map(i => `<div class="mini-item" style="height:12px;background:#888;border-radius:3px;opacity:0;width:${90-i*12}%;"></div>`).join('')}
          </div>
        `,
      },
      {
        depth: 5,
        label: 'Intent object',
        token: 'motion.appear [frontier]',
        value: '{\n  from: { opacity:0, y:8 },\n  to:   { opacity:1, y:0 },\n  spring: "{motion.spring.gentle}",\n  reducedMotion: "instant-fade"\n}',
        description: 'A complete behavioral description. Platform resolver determines property mapping. Not yet implemented.',
        frontier: true,
        animate: (el) => el.animate([{ opacity: 0, transform: 'translateY(8px)' }, { opacity: 1, transform: 'translateY(0)' }], { duration: 400, easing: 'cubic-bezier(0,0,0.2,1)', fill: 'forwards' }),
      },
    ];

    const panelHtml = panels.map((p, idx) => `
      <div style="
        background: ${p.frontier ? '#fffdf0' : '#fff'};
        border: 1px solid ${p.frontier ? '#f0c040' : '#e8e8e8'};
        border-radius: 8px; padding: 20px; flex: 1; min-width: 200px;
        display: flex; flex-direction: column; gap: 12px;
      ">
        <div>
          <div style="font-size: 10px; font-weight: 600; color: #aaa; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 4px;">Depth ${p.depth}</div>
          <div style="font-size: 14px; font-weight: 700; color: #111; margin-bottom: 4px;">${p.label}</div>
          <div style="font-family: 'SF Mono', 'Fira Code', monospace; font-size: 11px; color: #0055bb; margin-bottom: 8px;">${p.token}</div>
          <pre style="font-family: 'SF Mono', 'Fira Code', monospace; font-size: 11px; background: #f5f5f5; padding: 10px 12px; border-radius: 5px; white-space: pre-wrap; color: #333; margin: 0;">${p.value}</pre>
        </div>
        <div style="font-size: 12px; color: #777; line-height: 1.5; flex: 1;">${p.description}</div>
        <div style="display: flex; align-items: center; justify-content: center; min-height: 48px;">
          ${p.customRef || `<div id="depth-box-${idx}" style="width: 60px; height: 36px; background: #888; border-radius: 5px; display:flex;align-items:center;justify-content:center;color:#fff;font-size:10px;font-weight:600;opacity:1;"></div>`}
        </div>
        <button data-depth="${idx}" style="
          padding: 7px 14px; background: ${p.frontier ? '#856404' : '#111'};
          color: #fff; font-size: 12px; font-weight: 600; border-radius: 6px;
          cursor: pointer; border: none; font-family: inherit; width: 100%;
        ">Play</button>
      </div>
    `).join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${baseStyles}
        [data-depth]:hover { opacity: 0.85; }
      </style>
      <div class="page">
        <div class="page-title">Motion / Matrix</div>
        <div class="page-subtitle">Depth progression</div>
        <div class="page-description">
          How composition depth increases from a raw scalar to a complete behavioral description.
          Click Play on any panel to animate a reference element with that token's resolved output.
        </div>
        <div style="display: flex; gap: 12px; flex-wrap: wrap; align-items: stretch;">
          ${panelHtml}
        </div>
      </div>
    `;

    el.querySelectorAll('[data-depth]').forEach((btn) => {
      btn.addEventListener('click', () => {
        const idx = parseInt(btn.dataset.depth, 10);
        const panel = panels[idx];
        const box = el.querySelector(`#depth-box-${idx}`);

        if (panel.customRef) {
          // Stagger panel: animate the mini-items
          const miniItems = btn.parentElement.querySelectorAll('.mini-item');
          miniItems.forEach((item, i) => {
            item.style.opacity = '0';
            item.style.transform = 'translateY(6px)';
            item.animate(
              [{ opacity: 0, transform: 'translateY(6px)' }, { opacity: 1, transform: 'translateY(0)' }],
              { duration: 300, easing: 'cubic-bezier(0,0,0.2,1)', delay: i * 20, fill: 'forwards' }
            );
          });
        } else if (box) {
          box.style.opacity = '1';
          box.style.transform = 'none';
          setTimeout(() => { panel.animate(box); }, 20);
        }
      });
    });

    return el;
  },
};
